import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {

    /**
     * Helper function to check if a character is a lowercase English letter.
     */
    private static boolean isLetter(char c) {
        return c >= 'a' && c <= 'z';
    }

    /**
     * Solves the word counting problem.
     */
    public static long[] solve(String[] chunks, String[] queries) {
        // 1. Construct s
        StringBuilder sBuilder = new StringBuilder();
        for (String chunk : chunks) {
            sBuilder.append(chunk);
        }
        String s = sBuilder.toString();

        if (s.isEmpty()) {
            return new long[queries.length];
        }

        // 2. Tokenize s into words and count them
        Map<String, Integer> wordCounts = new HashMap<>();
        int N = s.length();
        StringBuilder currentToken = new StringBuilder();

        for (int i = 0; i < N; i++) {
            char c = s.charAt(i);

            if (isLetter(c)) {
                // Case 1: Letter found, always appends to the current token
                currentToken.append(c);
            } else if (c == '-') {
                // Case 3: Hyphen found, check validity based on neighbors in s
                boolean isValidHyphen = false;
                // Must not be at boundaries AND both neighbors must be letters
                if (i > 0 && i < N - 1) {
                    char prev = s.charAt(i - 1);
                    char next = s.charAt(i + 1);
                    if (isLetter(prev) && isLetter(next)) {
                        isValidHyphen = true;
                    }
                }

                if (isValidHyphen) {
                    currentToken.append(c);
                } else {
                    // Invalid hyphen acts as a separator
                    if (currentToken.length() > 0) {
                        // Process the token formed before this invalid hyphen
                        String word = currentToken.toString();
                        wordCounts.put(word, wordCounts.getOrDefault(word, 0) + 1);
                        currentToken.setLength(0);
                    }
                    // Skip the invalid hyphen
                }
            } else {
                // Case 2: General separator (non-letter, non-hyphen)
                if (currentToken.length() > 0) {
                    // Process the token formed before this separator
                    String word = currentToken.toString();
                    wordCounts.put(word, wordCounts.getOrDefault(word, 0) + 1);
                    currentToken.setLength(0);
                }
                // Skip the separator
            }
        }

        // Process any remaining token at the end of s
        if (currentToken.length() > 0) {
            String word = currentToken.toString();
            wordCounts.put(word, wordCounts.getOrDefault(word, 0) + 1);
        }

        // 4. Generate the result array
        long[] ans = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            String query = queries[i];
            // Since queries[i] is guaranteed to be an effective word, 
            // it must be present in our count map if it appears in s.
            ans[i] = wordCounts.getOrDefault(query, 0);
        }

        return ans;
    }
}

